package com.moushaifahbank.servlet; import javax.servlet.*;import javax.servlet.annotation.*;import javax.servlet.http.*;import java.io.*;import java.util.*;import com.moushaifahbank.util.*;import com.moushaifahbank.model.*; @WebServlet("/dashboard") public class DashboardServlet extends HttpServlet{UserDAO dao=new UserDAO(); protected void doGet(HttpServletRequest r,HttpServletResponse p)throws ServletException,IOException{Long uid=(Long)r.getSession().getAttribute("userId"); if(uid==null){p.sendRedirect("login");return;} User u=dao.findById(uid); List<Account> acc=dao.accounts(uid); r.setAttribute("user",u);r.setAttribute("accounts",acc); if(!acc.isEmpty())r.setAttribute("transactions",dao.transactions(acc.get(0).getId())); r.getRequestDispatcher("/WEB-INF/views/dashboard.jsp").forward(r,p);}}
